def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2:
            priorities[i] = np.inf
            continue
        base_score = np.sin(ratio * np.pi) + np.log1p(cap)
        complexity_factor = 1.0
        decay = 1.0
        penalty = 0.0
        reward = 0.0
        for j in range(1, 15):
            if j % 4 == 0:
                complexity_factor *= 1.03 + 0.005 * j
            elif j % 7 == 0:
                complexity_factor *= 0.97 - 0.004 * j
            exp_term = np.exp(-((ratio - 0.1 * j)**2) * 10)
            base_score += (j * cap**0.3) * exp_term * complexity_factor / (j+1)
            if cap % (j+1) == 0 and j % 3 == 1:
                penalty += np.cos(ratio * j) * (j / (cap + 1))
            if (cap * j + item * j) % 11 == 0:
                penalty -= np.sqrt(j + ratio)
            if ratio < 0.25 and j % 2 == 0:
                reward += (j**1.5) / (1 + np.sqrt(j * cap))
            if j == 10:
                for k in range(1, 8):
                    val = (cap + item * k) % (k+3)
                    if val == 0:
                        reward += np.log1p(k * val + 1)
                    else:
                        penalty += np.tanh(val / (k+1))
            if ratio > 0.7 and j % 5 == 0:
                decay *= 0.92 + 0.01 * j
            elif ratio < 0.1 and j % 4 == 3:
                decay *= 1.07 - 0.015 * j
        priority_score = base_score + 1.5 * reward - 2.0 * penalty
        priority_score *= decay
        if priority_score <= 0:
            priorities[i] = -priority_score * (np.sqrt(cap) + np.log1p(item))
        else:
            if cap > item * 5:
                priorities[i] = -priority_score / (np.cbrt(cap) + 1) * (1 + ratio ** 1.5)
            else:
                priorities[i] = -priority_score / (cap + 5) * np.exp(-ratio**3)
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        if ratio > 0.9:
            priorities[i] *= 1.12
        elif ratio < 0.1:
            priorities[i] *= 0.78
        if abs(cap - item) < 2:
            priorities[i] *= 1.05
    return priorities
